'use client';
import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { ArrowLeft, Eye, Send, Edit3, RefreshCw, CheckCircle2, Mail, Smartphone, Monitor, User } from 'lucide-react';
import Link from 'next/link';
import { leadStore, calcSubscription } from '@/lib/leadStore';
import { fillTemplate, DRIP_SEQUENCE } from '@/lib/dripStore';

// ?? ?대찓??誘몃━蹂닿린 + 媛쒖씤???몄쭛 + ?뺤젙 諛쒖넚 UI ?????????????

const BASE_SUBJECT = '[IBS 踰뺣쪧] {company}?섏쓽 媛쒖씤?뺣낫泥섎━諛⑹묠 ??AI 由ъ뒪??遺꾩꽍 寃곌낵';
const BASE_PREHEADER = '媛쒖씤?뺣낫蹂댄샇踰??꾨컲 {issueCount}嫄?諛쒓껄. 吏湲??뺤씤?섏꽭??';

function buildHookEmailHtml(vars: Record<string, string>, customMsg: string): string {
    return `<!DOCTYPE html>
<html>
<body style="margin:0;padding:0;background:#f1f5f9;font-family:'Apple SD Gothic Neo',Pretendard,sans-serif">
<div style="max-width:600px;margin:0 auto;background:#f1f5f9;padding:24px 0">

  <!-- ?ㅻ뜑 -->
  <div style="background:#04091a;border-radius:16px 16px 0 0;padding:28px 32px;text-align:center">
    <p style="color:#c9a84c;font-size:24px;font-weight:900;margin:0">?뽳툘 IBS 踰뺣쪧?щТ??/p>
    <p style="color:#94a3b8;font-size:13px;margin:6px 0 0">?꾨옖李⑥씠利??꾨Ц 踰뺣쪧 ?쒕퉬??쨌 45,000媛쒖궗 ?먮Ц ?ㅼ쟻</p>
  </div>

  <!-- 由ъ뒪??諛곕꼫 -->
  <div style="background:#fef2f2;border-left:4px solid #f87171;padding:20px 32px;margin:0">
    <p style="color:#dc2626;font-size:15px;font-weight:900;margin:0 0 6px">?뵶 ${vars.riskLevel} 由ъ뒪????${vars.issueCount}嫄??꾨컲 媛?μ꽦 諛쒓껄</p>
    <p style="color:#374151;font-size:13px;margin:0">怨쇱쭠湲?理쒕? <strong>3,000留뚯썝</strong> 遺怨?媛????ぉ???ы븿?섏뼱 ?덉뒿?덈떎.</p>
  </div>

  <!-- 蹂몃Ц -->
  <div style="background:#fff;padding:28px 32px">
    <p style="color:#1e293b;font-size:15px;margin:0 0 16px">${vars.contactName} ?대떦?먮떂猿?</p>
    <p style="color:#374151;line-height:1.7;margin:0 0 20px">
      ?덈뀞?섏꽭?? IBS 踰뺣쪧?щТ?뚯엯?덈떎.<br/>
      <strong>${vars.company}</strong>??媛쒖씤?뺣낫泥섎━諛⑹묠??AI濡?遺꾩꽍??寃곌낵瑜??꾨떖?쒕┰?덈떎.
    </p>

    ${customMsg ? `<div style="background:#fef9ec;border-left:4px solid #c9a84c;padding:16px;margin-bottom:20px;border-radius:0 8px 8px 0">
      <p style="color:#92400e;font-size:13px;font-weight:bold;margin:0 0 4px">蹂?몄궗 硫붾え</p>
      <p style="color:#374151;font-size:13px;margin:0;line-height:1.6">${customMsg}</p>
    </div>` : ''}

    <!-- 遺꾩꽍 寃곌낵 ?뚯씠釉?-->
    <table style="width:100%;border-collapse:collapse;margin:0 0 24px">
      <thead>
        <tr style="background:#f8fafc">
          <th style="padding:10px 12px;text-align:left;color:#64748b;font-size:12px;border-bottom:2px solid #e2e8f0">??ぉ</th>
          <th style="padding:10px 12px;text-align:center;color:#64748b;font-size:12px;border-bottom:2px solid #e2e8f0">由ъ뒪??/th>
          <th style="padding:10px 12px;text-align:left;color:#64748b;font-size:12px;border-bottom:2px solid #e2e8f0">洹쇨굅</th>
        </tr>
      </thead>
      <tbody>
        <tr><td style="padding:10px 12px;font-size:13px;color:#1e293b;border-bottom:1px solid #f1f5f9">?섏쭛??ぉ 怨쇰떎?섏쭛</td><td style="padding:10px;text-align:center"><span style="background:#fef2f2;color:#dc2626;font-size:11px;font-weight:bold;padding:2px 8px;border-radius:20px">怨좎쐞??/span></td><td style="padding:10px 12px;font-size:12px;color:#64748b">媛쒕낫踰?짠16</td></tr>
        <tr><td style="padding:10px 12px;font-size:13px;color:#1e293b;border-bottom:1px solid #f1f5f9">?????쒓났 誘몃챸??/td><td style="padding:10px;text-align:center"><span style="background:#fef2f2;color:#dc2626;font-size:11px;font-weight:bold;padding:2px 8px;border-radius:20px">怨좎쐞??/span></td><td style="padding:10px 12px;font-size:12px;color:#64748b">媛쒕낫踰?짠17</td></tr>
        <tr><td style="padding:10px 12px;font-size:13px;color:#1e293b">蹂댁쑀湲곌컙 ?쇰? ?꾨씫</td><td style="padding:10px;text-align:center"><span style="background:#fffbeb;color:#d97706;font-size:11px;font-weight:bold;padding:2px 8px;border-radius:20px">二쇱쓽</span></td><td style="padding:10px 12px;font-size:12px;color:#64748b">媛쒕낫踰?짠21</td></tr>
      </tbody>
    </table>

    <!-- CTA -->
    <div style="text-align:center;padding:20px 0 8px">
      <a href="http://localhost:3000/landing?cid=${vars.leadId}" style="background:linear-gradient(135deg,#c9a84c,#e8c87a);color:#0a0e1a;text-decoration:none;padding:16px 36px;border-radius:10px;font-weight:900;font-size:15px;display:inline-block">
        臾대즺 遺꾩꽍 寃곌낵 ?꾩껜 蹂닿린 ??r
      </a>
    </div>
    <p style="text-align:center;color:#94a3b8;font-size:12px;margin:12px 0 0">踰꾪듉 ?대┃ ???ъ뾽?먮쾲?몃줈 濡쒓렇?명븯???꾩껜 寃곌낵瑜??뺤씤?섏떎 ???덉뒿?덈떎</p>
  </div>

  <!-- ?ㅼ쟻 諛곕꼫 -->
  <div style="background:#0f172a;padding:20px 32px;display:flex;justify-content:space-around;text-align:center">
    <div><p style="color:#c9a84c;font-size:20px;font-weight:900;margin:0">1,000??</p><p style="color:#64748b;font-size:11px;margin:4px 0 0">?먮Ц 湲곗뾽 ?묒떆??/p></div>
    <div><p style="color:#c9a84c;font-size:20px;font-weight:900;margin:0">80,000+</p><p style="color:#64748b;font-size:11px;margin:4px 0 0">踰뺣쪧 ?먮Ц 嫄댁닔</p></div>
    <div><p style="color:#c9a84c;font-size:20px;font-weight:900;margin:0">45,000+</p><p style="color:#64748b;font-size:11px;margin:4px 0 0">?뚯썝??/p></div>
  </div>

  <!-- ?뗮꽣 -->
  <div style="background:#04091a;border-radius:0 0 16px 16px;padding:16px 32px;text-align:center">
    <p style="color:#475569;font-size:11px;margin:0">IBS 踰뺣쪧?щТ??| ??쒕쾲??02-1234-5678 | <a href="#" style="color:#475569">?섏떊嫄곕?</a></p>
  </div>
</div>
</body>
</html>`;
}

export default function EmailPreviewPage({
    searchParams,
}: { searchParams: Promise<{ leadId?: string; embed?: string }> }) {
    const params = React.use(searchParams);
    const leadId = params.leadId || 'lead_001';
    const isEmbed = params.embed === 'true';
    const lead = leadStore.getById(leadId);
    const sub = calcSubscription(lead?.storeCount || 0);

    const vars: Record<string, string> = {
        company: lead?.companyName || '(二??섑뵆?뚯궗',
        contactName: lead?.contactName || '?대떦??,
        leadId,
        issueCount: String(lead?.issueCount || 0),
        riskLevel: lead?.riskLevel || 'HIGH',
        riskScore: String(lead?.riskScore || 0),
        storeCount: String(lead?.storeCount || 0),
        bizType: lead?.bizType || '',
        monthlyFee: sub.monthly.toLocaleString(),
    };

    const [subject, setSubject] = useState(fillTemplate(BASE_SUBJECT, vars));
    const [customMsg, setCustomMsg] = useState('');
    const [viewMode, setViewMode] = useState<'desktop' | 'mobile'>('desktop');
    const [editTab, setEditTab] = useState<'subject' | 'message'>('subject');
    const [sending, setSending] = useState(false);
    const [sent, setSent] = useState(false);

    const htmlPreview = buildHookEmailHtml(vars, customMsg);

    const handleSend = async () => {
        setSending(true);
        try {
            await fetch('/api/email', {
                method: 'POST',
                headers: { 'content-type': 'application/json' },
                body: JSON.stringify({ type: 'company_hook', leadId, lawyerNote: customMsg, customSubject: subject }),
            });
            setSent(true);
        } catch { alert('諛쒖넚 ?ㅻ쪟'); }
        setSending(false);
    };

    return (
        <div className={isEmbed ? 'px-2 py-3' : 'min-h-screen px-4 py-8 max-w-[1600px] mx-auto'} style={{ background: '#f8f9fc' }}>
            {/* ?곷떒 ?ㅻ뜑 ??embed ???④? */}
            {!isEmbed && (
                <div className="flex items-center justify-between mb-6">
                    <div className="flex items-center gap-4">
                        <Link href="/admin/leads">
                            <button className="flex items-center gap-1.5 text-sm font-medium rounded-lg px-3 py-1.5 transition-colors hover:bg-slate-100" style={{ color: '#64748b' }}>
                                <ArrowLeft className="w-4 h-4" /> 由щ뱶 紐⑸줉
                            </button>
                        </Link>
                        <div className="h-5 w-px" style={{ background: '#d1d5db' }} />
                        <div>
                            <span className="text-base font-black" style={{ color: '#1e293b' }}>?대찓??誘몃━蹂닿린 ??{lead?.companyName}</span>
                            <span className="ml-2 text-xs px-2 py-0.5 rounded-full font-bold" style={{ background: '#fef2f2', color: '#dc2626', border: '1px solid #fca5a5' }}>
                                {lead?.riskLevel} {lead?.issueCount}嫄?r
                            </span>
                        </div>
                    </div>
                    <div className="flex items-center gap-3">
                        {/* 酉??좉? */}
                        <div className="flex rounded-lg overflow-hidden" style={{ border: '1px solid #d1d5db' }}>
                            {(['desktop', 'mobile'] as const).map(m => (
                                <button key={m} onClick={() => setViewMode(m)}
                                    className="px-3 py-1.5 text-xs font-bold transition-colors"
                                    style={{ background: viewMode === m ? '#fffbeb' : '#ffffff', color: viewMode === m ? '#b8960a' : '#94a3b8', borderRight: m === 'desktop' ? '1px solid #d1d5db' : 'none' }}>
                                    {m === 'desktop' ? <Monitor className="w-4 h-4" /> : <Smartphone className="w-4 h-4" />}
                                </button>
                            ))}
                        </div>
                        {sent ? (
                            <div className="flex items-center gap-1.5 px-4 py-2 rounded-lg text-sm font-bold"
                                style={{ background: '#dcfce7', color: '#16a34a', border: '1px solid #86efac' }}>
                                <CheckCircle2 className="w-4 h-4" /> 諛쒖넚 ?꾨즺!
                            </div>
                        ) : (
                            <button onClick={handleSend} disabled={sending}
                                className="flex items-center gap-2 px-5 py-2 rounded-lg font-black text-sm disabled:opacity-50"
                                style={{ background: 'linear-gradient(135deg,#c9a84c,#e8c87a)', color: '#0a0e1a' }}>
                                {sending ? <RefreshCw className="w-4 h-4 animate-spin" /> : <Send className="w-4 h-4" />}
                                諛쒖넚 ?뺤젙
                            </button>
                        )}
                    </div>
                </div>
            )}

            {/* 硫붿씤 ?덉씠?꾩썐 */}
            <div className="flex gap-5" style={{ minHeight: 'calc(100vh - 160px)' }}>
                {/* 醫? ?몄쭛 ?⑤꼸 */}
                <div className="w-80 flex-shrink-0 overflow-y-auto p-5 space-y-4 rounded-2xl"
                    style={{ background: '#ffffff', border: '1px solid #e5e7eb', boxShadow: '0 1px 4px rgba(0,0,0,0.06)' }}>
                    <div>
                        <p className="text-xs font-black uppercase tracking-wider mb-3" style={{ color: '#94a3b8' }}>?섏떊 ?뺣낫</p>
                        <div className="space-y-2 text-sm">
                            <div className="flex items-center gap-2">
                                <User className="w-3.5 h-3.5 flex-shrink-0" style={{ color: '#94a3b8' }} />
                                <span style={{ color: '#1e293b' }}>{lead?.contactName}</span>
                                <span style={{ color: '#64748b' }}>({lead?.contactEmail})</span>
                            </div>
                            <div className="flex items-center gap-2">
                                <Mail className="w-3.5 h-3.5 flex-shrink-0" style={{ color: '#94a3b8' }} />
                                <span style={{ color: '#475569' }}>{lead?.companyName}</span>
                            </div>
                        </div>
                    </div>

                    <div className="h-px" style={{ background: '#e5e7eb' }} />

                    {/* ?쒕ぉ ?몄쭛 */}
                    <div>
                        <label className="text-xs font-black uppercase tracking-wider mb-2 block" style={{ color: '#94a3b8' }}>
                            ?대찓???쒕ぉ
                        </label>
                        <textarea value={subject} onChange={e => setSubject(e.target.value)} rows={3}
                            className="w-full p-3 rounded-lg outline-none text-sm resize-none"
                            style={{ background: '#f8f9fc', border: '1px solid #e5e7eb', color: '#1e293b', lineHeight: 1.5 }} />
                    </div>

                    {/* 蹂?몄궗 異붽? 硫붿떆吏 */}
                    <div>
                        <label className="text-xs font-black uppercase tracking-wider mb-2 block" style={{ color: '#94a3b8' }}>
                            ?륅툘 媛쒖씤??硫붿떆吏 (?좏깮)
                        </label>
                        <textarea value={customMsg} onChange={e => setCustomMsg(e.target.value)} rows={5}
                            placeholder="?대떦?먯뿉寃??꾪븷 硫붿떆吏瑜??낅젰?섎㈃ ?대찓??蹂몃Ц???ы븿?⑸땲??.."
                            className="w-full p-3 rounded-lg outline-none text-sm resize-none"
                            style={{ background: '#f8f9fc', border: '1px solid #e5e7eb', color: '#1e293b', lineHeight: 1.6 }} />
                    </div>

                    <div className="h-px" style={{ background: '#e5e7eb' }} />

                    {/* 媛쒖씤??URL */}
                    <div>
                        <label className="text-xs font-black uppercase tracking-wider mb-2 block" style={{ color: '#94a3b8' }}>
                            媛쒖씤??URL
                        </label>
                        <div className="p-3 rounded-lg text-xs break-all"
                            style={{ background: '#fffbeb', border: '1px solid #fde68a', color: '#b8960a' }}>
                            /landing?cid={leadId}
                        </div>
                        <p className="text-xs mt-1" style={{ color: '#94a3b8' }}>?대┃ ???대떦 湲곗뾽 遺꾩꽍 寃곌낵 ?쒕뵫 ?대┝</p>
                    </div>

                    {/* ?쒕┰ 罹좏럹???덈궡 */}
                    <div className="p-3 rounded-lg" style={{ background: '#eff6ff', border: '1px solid #bfdbfe' }}>
                        <p className="text-xs font-black mb-1" style={{ color: '#3b82f6' }}>?뱟 ?쒕┰ 罹좏럹???덉빟</p>
                        <p className="text-xs" style={{ color: '#64748b' }}>誘멸껐????D+1쨌4쨌8쨌14쨌21쨌30??踰뺣쪧?먮즺 ?먮룞 諛쒖넚</p>
                    </div>
                </div>

                {/* ?? HTML 誘몃━蹂닿린 */}
                <div className="flex-1 overflow-y-auto p-6 rounded-2xl" style={{ background: '#e2e8f0', border: '1px solid #d1d5db' }}>
                    <div className="mb-4 text-center">
                        <span className="text-xs font-bold px-3 py-1.5 rounded-full"
                            style={{ background: '#ffffff', color: '#64748b', border: '1px solid #d1d5db' }}>
                            ?쒕ぉ: {subject}
                        </span>
                    </div>
                    <div className={`mx-auto ${viewMode === 'mobile' ? 'max-w-sm' : 'max-w-2xl'} rounded-2xl overflow-hidden shadow-2xl`}>
                        <iframe
                            srcDoc={htmlPreview}
                            className="w-full"
                            style={{ height: viewMode === 'mobile' ? '700px' : '900px', border: 'none' }}
                            title="?대찓??誘몃━蹂닿린"
                        />
                    </div>
                </div>
            </div>
        </div>
    );
}

'use client';
import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { ArrowLeft, Phone, Mail, Globe, Building2, AlertTriangle, CheckCircle2, Clock, MessageSquare, Plus, Eye } from 'lucide-react';
import Link from 'next/link';
import { leadStore, calcSubscription, type Lead, type LeadMemo, type LeadStatus } from '@/lib/leadStore';

const STATUS_LABEL: Record<string, string> = {
    pending: '?湲?, analyzed: '遺꾩꽍?꾨즺', sales_confirmed: '?곸뾽而⑦럩',
    lawyer_confirmed: '蹂?몄궗而⑦럩', emailed: '諛쒖넚?꾨즺', in_contact: '?곕씫以?,
    contracted: '怨꾩빟?꾨즺', failed: '?ㅽ뙣',
};

export default function LeadDetailPage({ params }: { params: Promise<{ id: string }> | { id: string } }) {
    const [lead, setLead] = useState<Lead | null>(null);
    const [memoText, setMemoText] = useState('');
    const [storeCount, setStoreCount] = useState(0);
    const [resolvedId, setResolvedId] = useState('');

    useEffect(() => {
        // Next.js 15: params may be a Promise
        Promise.resolve(params).then(p => {
            const id = p.id;
            setResolvedId(id);
            const l = leadStore.getById(id);
            if (l) { setLead(l); setStoreCount(l.storeCount); }
        });
    }, []);

    if (!lead) return (
        <div className="min-h-screen flex items-center justify-center" style={{ background: '#04091a' }}>
            <p style={{ color: 'rgba(240,244,255,0.4)' }}>由щ뱶瑜?李얠쓣 ???놁뒿?덈떎</p>
        </div>
    );

    const sub = calcSubscription(storeCount);

    const addMemo = () => {
        if (!memoText.trim()) return;
        leadStore.addMemo(lead.id, { author: '?곸뾽?', content: memoText });
        setLead(leadStore.getById(lead.id)!);
        setMemoText('');
    };



    return (
        <div className="min-h-screen pt-20 pb-12" style={{ background: '#04091a' }}>
            <div className="max-w-5xl mx-auto px-4">
                {/* ?ㅻ줈媛湲?*/}
                <Link href="/admin/leads">
                    <button className="flex items-center gap-2 text-sm mb-6" style={{ color: 'rgba(240,244,255,0.4)' }}>
                        <ArrowLeft className="w-4 h-4" /> ?곸뾽 由щ뱶 紐⑸줉
                    </button>
                </Link>

                <div className="grid md:grid-cols-3 gap-6">
                    {/* ?뚯궗 ?뺣낫 */}
                    <div className="md:col-span-2 space-y-4">
                        <div className="p-6 rounded-2xl" style={{ background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.07)' }}>
                            <div className="flex items-center justify-between mb-4">
                                <h1 className="text-xl font-black" style={{ color: '#f0f4ff' }}>{lead.companyName}</h1>
                                <span className="text-sm px-3 py-1 rounded-full font-bold"
                                    style={{ background: 'rgba(201,168,76,0.1)', color: '#c9a84c' }}>
                                    {STATUS_LABEL[lead.status]}
                                </span>
                            </div>
                            <div className="grid grid-cols-2 gap-3 text-sm">
                                {[
                                    { icon: Globe, label: '?꾨찓??, value: lead.domain },
                                    { icon: Building2, label: '?낆쥌', value: lead.bizType },
                                    { icon: Phone, label: '?꾪솕', value: lead.contactPhone },
                                    { icon: Mail, label: '?대찓??, value: lead.contactEmail },
                                    { icon: Building2, label: '?대떦??, value: lead.contactName },
                                    { icon: Building2, label: '媛留뱀젏??, value: `${lead.storeCount}媛? },
                                ].map(({ icon: Icon, label, value }) => (
                                    <div key={label} className="flex items-center gap-2">
                                        <Icon className="w-4 h-4 flex-shrink-0" style={{ color: 'rgba(240,244,255,0.3)' }} />
                                        <span style={{ color: 'rgba(240,244,255,0.4)' }}>{label}:</span>
                                        <span style={{ color: '#f0f4ff' }}>{value}</span>
                                    </div>
                                ))}
                            </div>
                            {lead.privacyUrl && (
                                <a href={lead.privacyUrl} target="_blank" rel="noreferrer"
                                    className="flex items-center gap-1.5 mt-3 text-xs" style={{ color: '#c9a84c' }}>
                                    <Globe className="w-3 h-3" /> 媛쒖씤?뺣낫泥섎━諛⑹묠 ?먮Ц ??r
                                </a>
                            )}
                        </div>

                        {/* 由ъ뒪???붿빟 */}
                        {lead.riskLevel && (
