                        <div><label style={labelStyle}>?ъ뾽?먮쾲??/label>{F('bizNumber')}</div>
                        <div><label style={labelStyle}>?대떦??/label>{F('contactName')}</div>
                        <div><label style={labelStyle}>?대찓??/label>{F('contactEmail')}</div>
                        <div><label style={labelStyle}>?꾪솕踰덊샇</label>{F('contactPhone')}</div>
                        <div><label style={labelStyle}>媛留뱀젏??/label>{F('storeCount')}</div>
                        <div><label style={labelStyle}>?낆쥌</label>{F('bizType')}</div>
                        <div><label style={labelStyle}>?ъ뾽?뺥깭</label>{F('bizCategory')}</div>
                        <div><label style={labelStyle}>?꾨찓??/label>{F('domain')}</div>
                        <div><label style={labelStyle}>媛쒖씤?뺣낫URL</label>{F('privacyUrl')}</div>
                    </div>

                    <div className="grid grid-cols-2 gap-6">
                        {/* 硫붾え */}
                        <div>
                            <p className="text-xs font-bold mb-2 flex items-center gap-1.5" style={{ color: T.sub }}>
                                <MessageSquare className="w-3.5 h-3.5" />硫붾え
                            </p>
                            <div className="flex gap-1.5">
                                <textarea value={newMemo} onChange={e => setNewMemo(e.target.value)}
                                    onKeyDown={e => e.key === 'Enter' && !e.shiftKey && (e.preventDefault(), handleAddMemo())}
                                    rows={5} placeholder="硫붾え ?낅젰 ??Enter..." style={taStyle} />
