                                <th className="py-3 px-4 text-left text-xs font-black" style={{ color: '#b8960a' }}>?대떦??/th>
                                <th className="py-3 px-4 text-left text-xs font-black" style={{ color: '#b8960a' }}>媛?낆씪</th>
                                <th className="py-3 px-4 text-left text-xs font-black" style={{ color: '#b8960a' }}>寃쎄낵??/th>
                                <th className="py-3 px-4 text-left text-xs font-black" style={{ color: '#b8960a' }}>吏꾪뻾瑜?/th>
