const REQUIRED_HEADERS = ['?뚯궗紐?, '?ъ뾽?먮쾲??, '?대떦?먮챸', '?대찓??, '?꾪솕踰덊샇', '媛留뱀젏??, '?낆쥌', '?ъ뾽?뺥깭', '?꾨찓??, '媛쒖씤?뺣낫泥섎━諛⑹묠URL'];
const SAMPLE_CSV = `?뚯궗紐??ъ뾽?먮쾲???대떦?먮챸,?대찓???꾪솕踰덊샇,媛留뱀젏???낆쥌,?ъ뾽?뺥깭,?꾨찓??媛쒖씤?뺣낫泥섎━諛⑹묠URL
(二??먮윭??123-45-67890,源留덉???kim@salady.co.kr,010-1234-5678,180,?몄떇,?꾨옖李⑥씠利?salady.co.kr,https://salady.co.kr/privacy
(二?硫붽?而ㅽ뵾,234-56-78901,?댁슫??lee@megacoffee.co.kr,010-2345-6789,2800,移댄럹,?꾨옖李⑥씠利?megacoffee.co.kr,https://megacoffee.co.kr/privacy`;

export default function UploadPage() {
    const router = useRouter();
    const fileInputRef = useRef<HTMLInputElement>(null);
    const [isDragging, setIsDragging] = useState(false);
    const [fileName, setFileName] = useState<string | null>(null);
    const [parsedRows, setParsedRows] = useState<ParsedRow[]>([]);
    const [headers, setHeaders] = useState<string[]>([]);
    const [error, setError] = useState<string | null>(null);
    const [step, setStep] = useState<'upload' | 'preview' | 'done'>('upload');
    const [uploadResult, setUploadResult] = useState<{ total: number; valid: number } | null>(null);
    const [selectedRows, setSelectedRows] = useState<Set<number>>(new Set());

    // ?? CSV ?뚯떛 ??????????????????????????????????????????????
    const parseCSV = useCallback((text: string) => {
        try {
            const lines = text.split(/\r?\n/).filter(Boolean);
            if (lines.length < 2) {
                setError('?곗씠?곌? ?놁뒿?덈떎. ?ㅻ뜑 ?됯낵 理쒖냼 1媛쒖쓽 ?곗씠???됱씠 ?꾩슂?⑸땲??');
                return;
            }

            const headerLine = lines[0].split(',').map(h => h.trim().replace(/^"|"$/g, ''));
            setHeaders(headerLine);

            // 1李? 湲곕낯 ?뚯떛
            const rows: ParsedRow[] = lines.slice(1).map(line => {
                const cols = line.split(',').map(c => c.trim().replace(/^"|"$/g, ''));
                const companyName = cols[0] ?? '';
                const bizNumber = cols[1] ?? '';
                const storeCount = parseInt(cols[5]) || 0;
                const errors: string[] = [];
                if (!companyName) errors.push('?뚯궗紐?遺??);
                if (!bizNumber) errors.push('?ъ뾽?먮쾲??遺??);
                const valid = errors.length === 0;

                return {
                    companyName,
                    bizNumber,
                    contactName: cols[2] ?? '',
                    contactEmail: cols[3] ?? '',
                    contactPhone: cols[4] ?? '',
                    storeCount,
                    bizType: cols[6] ?? '湲고?',
                    bizCategory: cols[7] ?? '',
                    domain: cols[8] ?? '',
                    privacyUrl: cols[9] ?? '',
                    valid,
                    error: valid ? undefined : errors.join(', '),
