            // 2李? 以묐났 & ?ъ뾽?뺥깭 寃쎄퀬 泥댄겕
            const seenBizNumbers = new Map<string, number>();
            const seenNames = new Map<string, number>();
            rows.forEach((row, i) => {
                if (!row.valid) return;
                const warnings: string[] = [];
                // ?ъ뾽?먮쾲??以묐났 泥댄겕
                if (row.bizNumber) {
                    const prev = seenBizNumbers.get(row.bizNumber);
                    if (prev !== undefined) {
                        warnings.push(`?ъ뾽?먮쾲??以묐났 (#${prev + 1}??`);
                    } else {
                        seenBizNumbers.set(row.bizNumber, i);
                    }
                }
                // ?뚯궗紐?以묐났 泥댄겕
                if (row.companyName) {
                    const prev = seenNames.get(row.companyName);
                    if (prev !== undefined) {
