            setSelectedRows(new Set(rows.map((_, i) => i).filter(i => rows[i].valid && !rows[i].warning)));
            setStep('preview');
            setError(null);
        } catch {
            setError('?뚯씪 ?뚯떛 ?ㅻ쪟. CSV ?뺤떇???뺤씤?댁＜?몄슂.');
