                    {overdue && <span style={{ color: '#dc2626' }}> (D+{Math.abs(days)} 珥덇낵)</span>}
                    {d.completed && d.completedAt && <span style={{ color: '#94a3b8' }}> 쨌 ?꾨즺 {d.completedAt}</span>}
                </p>
            </div>
        </div>
    );
}

