                c.updatedAt = new Date().toISOString();
                save(all);
                const modeText = result.mock ? '(Mock 紐⑤뱶)' : '(??諛쒖넚)';
                addLog({ type: 'auto_email', label: `?대찓???먮룞 諛쒖넚 ${modeText}`, companyName: c.name, detail: `蹂?몄궗 而⑦럩 ??${c.email}濡??먮룞 諛쒖넚 ?꾨즺 ${modeText}` });
